import anthropic, json

client = anthropic.Anthropic()

GATE_CHECK_TOOL = {
    "name": "gate_check_result",
    "description": "Return the result of a PRD gate check.",
    "input_schema": {
        "type": "object",
        "properties": {
            "gate":          {"type": "string", "enum": ["gate1","gate2","gate3","gate4"]},
            "passed":        {"type": "boolean"},
            "blocking_issues": {"type": "array", "items": {"type": "string"}},
            "advisory_notes":  {"type": "array", "items": {"type": "string"}},
            "verdict":       {"type": "string"}
        },
        "required": ["gate","passed","blocking_issues","advisory_notes","verdict"]
    }
}

def run_gate_check(gate: str, prd_section_text: str, gate_criteria: list[str]) -> dict:
    """
    Run one PRD gate check by asking Claude to evaluate a PRD section against criteria.
    Returns a gate_check_result dict with blocking issues and advisory notes.
    """
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=800,
        tools=[GATE_CHECK_TOOL],
        tool_choice={"type": "any"},
        messages=[{
            "role": "user",
            "content": (
                f"PRD Gate: {gate}\n"
                f"Blocking criteria (any failure = gate does not pass):\n"
                + "\n".join(f"- {c}" for c in gate_criteria) + "\n\n"
                f"PRD section text to evaluate:\n{prd_section_text}\n\n"
                "Call gate_check_result. List every blocking issue you found. "
                "If no blocking issues, passed=true. Advisory notes are non-blocking."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use" and block.name == "gate_check_result":
            return block.input
    return {"gate": gate, "passed": False, "blocking_issues": ["Gate check failed to return result"]}

GATE_CRITERIA = {
    "gate1": [
        "System Prompt Specification section is present and non-empty",
        "Behavioural Contracts section is present and non-empty",
        "Eval Plan section is present and non-empty",
        "Token Budget section is present and non-empty",
        "Failure Mode Registry section is present and non-empty",
        "No section contains only placeholder text (e.g. '[TBD]', '[To be filled]')",
    ],
    "gate2": [
        "Every must_do item is a concrete, testable assertion (not aspirational)",
        "Every must_not_do item is a concrete, testable constraint",
        "Non-negotiable constraints are listed as a separate section",
        "At least 5 boundary condition scenarios are defined with expected behaviours",
    ],
    "gate3": [
        "Every must/must-not maps to at least one named eval test",
        "All P0 eval tests have a named owner",
        "Launch threshold is stated (e.g. 'P0 tests must pass at ≥ 95% on 100-sample suite')",
        "Judge type (exact_match, llm_judge, human_review) is specified for each test",
    ],
    "gate4": [
        "Every CRITICAL and HIGH failure mode has a documented mitigation",
        "User data handling (logging, retention, PII) is documented",
        "Any use of user conversation data for model training is explicitly addressed",
    ],
}

# Run all four gates on a PRD
def run_full_prd_review(prd_sections: dict) -> dict:
    results = {}
    for gate, criteria in GATE_CRITERIA.items():
        section_text = prd_sections.get(gate, "")
        results[gate] = run_gate_check(gate, section_text, criteria)
    overall_passed = all(r["passed"] for r in results.values())
    return {"overall_passed": overall_passed, "gates": results}

