# Run as a GitHub Actions step or pre-commit hook.
# Validates that a PRD JSON file passes all four gates before merging.

import json, sys, re
from pathlib import Path

def load_prd(path: str) -> dict:
    return json.loads(Path(path).read_text())

def gate1_completeness(prd: dict) -> list[str]:
    """Gate 1: All required AI sections present and non-empty."""
    required = [
        "system_prompt_spec", "model_config", "behavioural_contract",
        "eval_plan", "token_budget", "failure_mode_registry", "observability"
    ]
    issues = []
    sections = prd.get("sections", {})
    for r in required:
        if r not in sections:
            issues.append(f"Missing section: {r}")
        elif not sections[r] or sections[r].strip() in ("[TBD]", "[To be filled]", ""):
            issues.append(f"Section '{r}' is empty or placeholder")
    return issues

def gate2_behaviour_spec(prd: dict) -> list[str]:
    """Gate 2: Behaviour spec items are testable."""
    issues = []
    spec = prd.get("sections", {}).get("behavioural_contract", {})
    if isinstance(spec, str):
        return ["behavioural_contract must be a structured object, not a string"]

    must_do = spec.get("must_do", [])
    must_not = spec.get("must_not_do", [])
    non_neg = spec.get("non_negotiable_constraints", [])
    boundaries = spec.get("boundary_conditions", [])

    ASPIRATIONAL = re.compile(r"\b(should|try to|strive to|aim to|be helpful|be accurate)\b", re.I)
    for item in must_do:
        if ASPIRATIONAL.search(item.get("assertion", "")):
            issues.append(f"must_do[{item.get('id')}]: aspirational language detected — rewrite as a concrete assertion")

    if not non_neg:
        issues.append("Non-negotiable constraints section is empty")
    if len(boundaries) < 3:
        issues.append(f"Only {len(boundaries)} boundary conditions defined — minimum 3 required")
    return issues

def gate3_eval_plan(prd: dict) -> list[str]:
    """Gate 3: Every P0 eval test has a named owner and a launch threshold is stated."""
    issues = []
    eval_plan = prd.get("sections", {}).get("eval_plan", {})
    if isinstance(eval_plan, str):
        return ["eval_plan must be a structured object"]

    tests = eval_plan.get("tests", [])
    p0_tests = [t for t in tests if t.get("priority") == "P0"]
    if not p0_tests:
        issues.append("No P0 tests defined in eval_plan")
    for t in p0_tests:
        if not t.get("owner"):
            issues.append(f"P0 test '{t.get('criterion_id')}' has no owner assigned")
        if not t.get("pass_criteria"):
            issues.append(f"P0 test '{t.get('criterion_id')}' has no pass_criteria")

    if not eval_plan.get("launch_threshold"):
        issues.append("launch_threshold not stated in eval_plan")
    return issues

def gate4_risk(prd: dict) -> list[str]:
    """Gate 4: All CRITICAL/HIGH failure modes have mitigations."""
    issues = []
    registry = prd.get("sections", {}).get("failure_mode_registry", [])
    if isinstance(registry, str):
        return ["failure_mode_registry must be a list"]

    for fm in registry:
        if fm.get("severity") in ("critical", "high") and not fm.get("mitigation"):
            issues.append(f"Failure mode '{fm.get('id')}' is {fm.get('severity')} but has no mitigation")
    return issues

def run_all_gates(prd_path: str) -> bool:
    prd = load_prd(prd_path)
    gate_fns = [gate1_completeness, gate2_behaviour_spec, gate3_eval_plan, gate4_risk]
    gate_names = ["Gate 1 (Completeness)", "Gate 2 (Behaviour)", "Gate 3 (Eval Plan)", "Gate 4 (Risk)"]
    passed = True
    for fn, name in zip(gate_fns, gate_names):
        issues = fn(prd)
        if issues:
            print(f"\n{name}: FAILED")
            for i in issues:
                print(f"  ✗ {i}")
            passed = False
        else:
            print(f"{name}: PASSED")
    return passed

if __name__ == "__main__":
    path = sys.argv[1] if len(sys.argv) > 1 else "prd.json"
    ok = run_all_gates(path)
    sys.exit(0 if ok else 1)
